"""Run session and result models."""

from __future__ import annotations

from typing import Literal

from pydantic import BaseModel, Field

from .state import ResearchState


class RunArtifacts(BaseModel):
    """Artifact paths generated by one run."""

    attempt_dir: str
    manifest_path: str
    events_path: str
    best_state_path: str
    report_md_path: str
    report_json_path: str
    lean_preflight_path: str
    rlm_notes_path: str | None = None


class RunSession(BaseModel):
    """Session metadata and status for one run."""

    run_id: str
    problem_id: str
    status: str
    config: dict = Field(default_factory=dict)
    lean_preflight: dict = Field(default_factory=dict)
    artifacts: RunArtifacts


class RunResult(BaseModel):
    """Final output of one solver run."""

    problem_id: str
    status: Literal[
        "verified_solution",
        "plausible_progress",
        "counterexample_found",
        "stalled",
        "failed",
    ]
    best_state: ResearchState
    report_path: str
    summary: str
    run_id: str | None = None
    attempt_dir: str | None = None
    artifacts: RunArtifacts | None = None
